// Extract event data from router payload
const input = $input.first().json;

const eventId = input.body?.event_id || input.event_id;
const projectId = input.body?.project_id || input.project_id;
const payload = input.body?.payload || input.payload || {};

const approvalId = payload.approval_id;
const channel = payload.channel || 'telegram';
const recipient = payload.recipient || null;

const stepKey = `approval_dispatch:${approvalId}`;

return {
  json: {
    event_id: eventId,
    project_id: projectId,
    approval_id: approvalId,
    channel: channel,
    recipient: recipient,
    step_key: stepKey
  }
};

// Build dispatch messages for all channels
const approval = $input.first().json;
const eventData = $('Parse Event Data').first().json;
const requestData = typeof approval.request_data === 'string' 
  ? JSON.parse(approval.request_data) 
  : approval.request_data || {};

const channel = eventData.channel;
const recipient = eventData.recipient;

// Extract data from request_data
const deviations = requestData.deviations || [];
const deviationCount = requestData.deviation_count || 0;
const additionalCount = requestData.additional_count || 0;
const confirmedCount = requestData.confirmed_count || 0;
const inspectionDate = requestData.inspection_date || '';
const finalizedBy = requestData.finalized_by || 'Bauleiter';

// Separate deviations and additionals
const deviationItems = deviations.filter(d => d.deviation_type && !d.is_additional);
const additionalItems = deviations.filter(d => d.is_additional);

// Map deviation types to labels
const deviationLabels = {
  'damage': 'Beschädigung',
  'wrong_product': 'Falsches Produkt',
  'missing': 'Fehlend',
  'quality': 'Qualitätsmangel',
  'dimension': 'Maßabweichung',
  'other': 'Sonstiges'
};

// Build deviation lines
const deviationLines = deviationItems.map(d => {
  const room = d.room_name || '';
  const pos = d.position_number ? `Pos ${d.position_number}` : '';
  const title = d.position_title || '';
  const label = deviationLabels[d.deviation_type] || d.deviation_type || '';
  const notes = d.notes ? `\n    ${d.notes}` : '';
  return `- ${room} · ${pos} ${title}: ${label}${notes}`;
}).join('\n');

// Build additional lines
const additionalLines = additionalItems.map(d => {
  const room = d.room_name || '';
  const nr = d.catalog_position_nr || '';
  const title = d.position_title || '';
  const notes = d.notes ? `\n    ${d.notes}` : '';
  return `- ${room} · ${nr} ${title}${notes}`;
}).join('\n');

// Address parts
const address = [approval.object_street, `${approval.object_zip || ''} ${approval.object_city || ''}`].filter(Boolean).join(', ');
const subject = `Erstbegehung ${approval.project_number} — ${approval.object_street}`;

// Plain text message (for email/whatsapp)
const plainMessage = [
  `Betreff: ${subject}`,
  '',
  'Sehr geehrte Damen und Herren,',
  '',
  `die Erstbegehung für das o.g. Objekt wurde am ${inspectionDate} durchgeführt.`,
  '',
  'Ergebnis:',
  confirmedCount ? `- ${confirmedCount} Positionen wie beauftragt bestätigt` : null,
  `- ${deviationCount} Abweichungen festgestellt`,
  `- ${additionalCount} nicht beauftragte Leistungen vorgefunden`,
  deviationItems.length ? '\nAbweichungen:' : null,
  deviationItems.length ? deviationLines : null,
  additionalItems.length ? '\nZusatzleistungen:' : null,
  additionalItems.length ? additionalLines : null,
  '',
  'Fotodokumentation liegt bei / kann angefordert werden.',
  '',
  'Mit freundlichen Grüßen',
  `${eventData.decided_by_name || finalizedBy}`,
  'Deine Baulöwen GmbH'
].filter(v => v !== null).join('\n');

// Telegram markdown message (shorter)
const telegramMessage = [
  `📋 *Erstbegehung ${approval.project_number}*`,
  `📍 ${approval.object_street}`,
  `📅 ${inspectionDate}`,
  '',
  confirmedCount ? `✅ ${confirmedCount} bestätigt` : null,
  deviationCount ? `⚠️ ${deviationCount} Abweichungen` : null,
  additionalCount ? `➕ ${additionalCount} Zusatzleistungen` : null,
  deviationItems.length ? '\n*Abweichungen:*' : null,
  ...deviationItems.map(d => {
    const label = deviationLabels[d.deviation_type] || d.deviation_type || '';
    return `• ${d.room_name || ''} · ${d.position_title || ''}: _${label}_`;
  }),
  additionalItems.length ? '\n*Zusatzleistungen:*' : null,
  ...additionalItems.map(d => {
    return `• ${d.room_name || ''} · ${d.catalog_position_nr || ''} ${d.position_title || ''}`;
  }),
  '',
  `_${eventData.decided_by_name || finalizedBy} · Deine Baulöwen GmbH_`
].filter(v => v !== null).join('\n');

// HTML email body
const deviationHtml = deviationItems.map(d => {
  const label = deviationLabels[d.deviation_type] || d.deviation_type || '';
  const notes = d.notes ? `<br><small>${d.notes}</small>` : '';
  return `<li>${d.room_name || ''} · Pos ${d.position_number || ''} ${d.position_title || ''}: <strong>${label}</strong>${notes}</li>`;
}).join('');

const additionalHtml = additionalItems.map(d => {
  const notes = d.notes ? `<br><small>${d.notes}</small>` : '';
  return `<li>${d.room_name || ''} · ${d.catalog_position_nr || ''} ${d.position_title || ''}${notes}</li>`;
}).join('');

const htmlBody = `
<p>Sehr geehrte Damen und Herren,</p>
<p>die Erstbegehung für das o.g. Objekt wurde am <strong>${inspectionDate}</strong> durchgeführt.</p>
<h3>Ergebnis</h3>
<ul>
${confirmedCount ? `<li>${confirmedCount} Positionen wie beauftragt bestätigt</li>` : ''}
<li>${deviationCount} Abweichungen festgestellt</li>
<li>${additionalCount} nicht beauftragte Leistungen vorgefunden</li>
</ul>
${deviationItems.length ? `<h3>Abweichungen</h3><ul>${deviationHtml}</ul>` : ''}
${additionalItems.length ? `<h3>Zusatzleistungen</h3><ul>${additionalHtml}</ul>` : ''}
<p>Fotodokumentation liegt bei / kann angefordert werden.</p>
<p>Mit freundlichen Grüßen<br>
${eventData.decided_by_name || finalizedBy}<br>
<strong>Deine Baulöwen GmbH</strong></p>
`;

return {
  json: {
    ...eventData,
    approval_id: approval.approval_id,
    project_id: approval.project_id,
    approval_type: approval.approval_type,
    project_number: approval.project_number,
    object_street: approval.object_street,
    client_name: approval.client_name,
    client_email: approval.client_email,
    deviation_count: deviationCount,
    additional_count: additionalCount,
    confirmed_count: confirmedCount,
    subject: subject,
    telegram_message: telegramMessage,
    plain_message: plainMessage,
    html_body: htmlBody,
    channel: channel,
    recipient: recipient
  }
};

// WhatsApp via Superchat API
// If Superchat is not configured, skip gracefully
const data = $input.first().json;

try {
  // Superchat integration would go here
  // For now, log and pass through
  return {
    json: {
      ...data,
      whatsapp_status: 'skipped',
      whatsapp_note: 'Superchat integration not yet configured — message not sent via WhatsApp'
    }
  };
} catch (err) {
  return {
    json: {
      ...data,
      whatsapp_status: 'skipped',
      whatsapp_note: `WhatsApp send failed: ${err.message}`
    }
  };
}

// Email dispatch — check if recipient exists
const data = $input.first().json;
const emailTo = data.recipient || data.client_email;

if (!emailTo) {
  // No email recipient — fallback to telegram with warning
  return {
    json: {
      ...data,
      email_fallback: true,
      email_note: 'Kein E-Mail-Empfänger — Fallback auf Telegram'
    }
  };
}

return {
  json: {
    ...data,
    email_to: emailTo,
    email_fallback: false
  }
};

